// tool_criarAgendamento v2 — HTTP wrapper pra llm-agent-api /agendar
// Valida inputs (mesma rigidez do v1) e monta payload pro HTTP.
// Regras clínicas, idempotência, criação de paciente: tudo no endpoint.
//
// Erros de validação são lançados (throw). O sub-workflow falha e o AI Agent
// recebe a mensagem como resultado da tool, podendo reagir (ex: pedir dado certo).

const input = $json || {};
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const DATE_RE = /^\d{4}-\d{2}-\d{2}$/;
const TIME_RE = /^([01]\d|2[0-3]):[0-5]\d(:[0-5]\d)?$/;

const norm = (v) => {
  if (v === undefined || v === null) return null;
  const s = String(v).trim();
  return s.length === 0 ? null : s;
};

const reqUuid = (v, name) => {
  const s = norm(v);
  if (!s || !UUID_RE.test(s)) {
    throw new Error(`${name} inválido ou ausente — esperado UUID, recebido: "${v ?? ''}"`);
  }
  return s;
};

const cliente_id     = reqUuid(input.cliente_id, 'cliente_id');
const medico_id      = reqUuid(input.medico_id, 'medico_id');
const atendimento_id = reqUuid(input.atendimento_id, 'atendimento_id');

const nome_completo = norm(input.nome_completo);
if (!nome_completo || nome_completo.length < 2) {
  throw new Error(`nome_completo ausente ou muito curto — recebido: "${input.nome_completo ?? ''}"`);
}

const data_nasc = norm(input.data_nascimento);
if (!data_nasc || !DATE_RE.test(data_nasc)) {
  throw new Error(`data_nascimento deve ser YYYY-MM-DD — recebido: "${input.data_nascimento ?? ''}"`);
}

const convenio = norm(input.convenio);
if (!convenio) {
  throw new Error(`convenio ausente`);
}

const data_ag = norm(input.data_agendamento);
if (!data_ag || !DATE_RE.test(data_ag)) {
  throw new Error(`data_agendamento deve ser YYYY-MM-DD — recebido: "${input.data_agendamento ?? ''}"`);
}

const hora_ag = norm(input.hora_agendamento);
if (!hora_ag || !TIME_RE.test(hora_ag)) {
  throw new Error(`hora_agendamento deve ser HH:MM[:SS] — recebido: "${input.hora_agendamento ?? ''}"`);
}

const celularRaw = norm(input.celular);
if (!celularRaw) {
  throw new Error(`celular ausente`);
}
const celular = celularRaw.replace(/\D/g, '');
if (celular.length < 10 || celular.length > 13) {
  throw new Error(`celular inválido — esperado 10-13 dígitos, recebido: "${celularRaw}" (após limpeza: "${celular}")`);
}

const telefone    = norm(input.telefone);
const observacoes = norm(input.observacoes);

// Payload pra llm-agent-api /agendar (campos alinhados com mapSchedulingData)
const payload = {
  cliente_id,
  paciente_nome:    nome_completo,
  data_nascimento:  data_nasc,
  convenio,
  telefone:         telefone || undefined,
  celular,
  medico_id,
  atendimento_id,
  data_consulta:    data_ag,
  hora_consulta:    hora_ag,
  observacoes:      observacoes || undefined,
};

return [{ json: { payload } }];

// Empacota o response do llm-agent-api num shape compatível com o tool v1.
// v1 retornava { ok, resultado } onde resultado vinha da RPC.
// Aqui resultado vira o JSON do response HTTP inteiro pra IA ler mensagem_usuario etc.

const resp = $input.first()?.json || null;

if (!resp) {
  return [{ json: { ok: false, mensagem: 'HTTP sem resposta.', resultado: null } }];
}

// success=true do llm-agent-api → ok=true
// success=false (regra clínica ou erro técnico) → ok=false
const ok = resp.success === true;

return [{ json: { ok, resultado: resp } }];
